def format_csv_output(data: list, columns: list, separator: str = ", ", include_header: bool = True) -> dict:
    """Format data as CSV string with proper escaping.

    Returns:
        dict: {'csv_string': str, 'row_count': int, 'column_count': int, 'validation': dict}
    """
    import csv
    from io import StringIO

    if not data:
        return {
            "csv_string": "",
            "row_count": 0,
            "column_count": len(columns),
            "validation": {"status": "warning", "message": "No data provided"}
        }

    output = StringIO()
    writer = csv.writer(output, quoting=csv.QUOTE_MINIMAL)

    # Write header
    if include_header:
        writer.writerow(columns)

    # Write data rows
    rows_written = 0
    for item in data:
        row = []
        for col in columns:
            value = item.get(col, "")

            # Handle list values (e.g., multiple artists)
            if isinstance(value, list):
                value = separator.join(str(v) for v in value)
            elif value is None:
                value = ""
            else:
                value = str(value)

            row.append(value)

        writer.writerow(row)
        rows_written += 1

    csv_string = output.getvalue()
    output.close()

    # Validation
    validation = {"status": "success", "message": "CSV formatted correctly"}
    if rows_written == 0:
        validation = {"status": "error", "message": "No rows written"}
    elif rows_written != len(data):
        validation = {"status": "warning", "message": f"Expected {len(data)} rows, wrote {rows_written}"}

    return {
        "csv_string": csv_string,
        "row_count": rows_written,
        "column_count": len(columns),
        "validation": validation
    }
